package com.template.mf; public class ApiResponse<T>{public int code;public String message;public String traceId;public T data; public static <T> ApiResponse<T> ok(T d){ApiResponse<T> r=new ApiResponse<>();r.code=0;r.message="OK";r.traceId=java.util.UUID.randomUUID().toString().replace("-","");r.data=d;return r;} public static <T> ApiResponse<T> fail(int c,String m){ApiResponse<T> r=new ApiResponse<>();r.code=c;r.message=m;r.traceId=java.util.UUID.randomUUID().toString().replace("-","");return r;} }
